    this.color = color;
    this.speed = speed;
  }

  // Method
  public void honk() {
    System.out.println("Beep beep!");
  }

  public static void main(String[] args) {
    Car myCar = new Car("Red", 100);
    myCar.honk();
    System.out.println("My car is " + myCar.color);
  }
}

